Greedy randomized adaptive search procedure using simulated annealing acceptance probability for marginal cost increases while prioritizing inserts into existing routes sorted by load proximity similarity before considering empties and new vehicles.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	existingNonEmpty := make([]int, 0, dispatch.AssignsLen)
	emptyExisting := make([]int, 0, dispatch.AssignsLen)
	newIdxStart := dispatch.AssignsLen
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			existingNonEmpty = append(existingNonEmpty, i)
		} else {
			emptyExisting = append(emptyExisting, i)
		}
	}
	Tinit := 1000.0
	T := Tinit
	for iterIdx, oidx := range orderIndices {
		ori := oris[oidx]
		des := dess[oidx]
		shipID := total_ship + oidx
		inserted := false
		type candidate struct {
			idx       int
			incr      float64
			isNew     bool
		}
		candList := make([]candidate, 0)
		allIndices := make([]int, 0, dispatch.AssignsLen+1)
		for i := 0; i < dispatch.AssignsLen; i++ {
			allIndices = append(allIndices, i)
		}
		allIndices = append(allIndices, newIdxStart)
		for _, idx := range allIndices {
			isNew := (idx == newIdxStart)
			var oldCost float64
			if !isNew {
				oldCost = dispatch.Assigns[idx].Cost
				ok := dispatch.Assigns[idx].AddShip(shipID, ori, des)
				if !ok {
					continue
				}
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost >= 0 {
					incr := dispatch.Assigns[idx].Cost - oldCost
					score := incr
					if incr <= 0 {
						score = 0
					} else {
						score = incr
					}
					candList = append(candList, candidate{idx: idx, incr: score, isNew: false})
				}
				dispatch.Assigns[idx].RemoveShip(shipID)
				dispatch.Assigns[idx].GenRoute()
			} else {
				if dispatch.AssignsLen >= MAXASSIGNS {
					continue
				}
				ok := dispatch.Assigns[idx].AddShip(shipID, ori, des)
				if !ok {
					continue
				}
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost >= 0 {
					baseDist := cal_dis(ori, des)
					initPenalty := baseDist * 2.5
					score := initPenalty + dispatch.Assigns[idx].Cost
					candList = append(candList, candidate{idx: idx, incr: score, isNew: true})
				}
				dispatch.Assigns[idx].RemoveShip(shipID)
				dispatch.Assigns[idx].GenRoute()
			}
		}
		Tcurrent := T * (1.0 - float64(iterIdx)/float64(len(orderIndices)+1)*0.8)
		const K = 5
		sort.Slice(candList, func(i, j int) bool {
			return candList[i].incr < candList[j].incr
		})
		selectedCand := -1
		minIncr := math.MaxFloat64
		for _, c := range candList {
			if c.incr < minIncr {
				minIncr = c.incr
			}
		}
		if len(candList) > 0 {
			considerSize := K
			if considerSize > len(candList) {
				considerSize = len(candList)
			}
			probSum := 0.0
			probs := make([]float64, considerSize)
			for i := 0; i < considerSize; i++ {
				delta := candList[i].incr - minIncr
				powVal := -delta / Tcurrent
				if powVal > 700 {
					powVal = 700
				}
				expV := math.Exp(powVal)
				if math.IsInf(expV, 0) || math.IsNaN(expV) {
					expV = 0
				}
				probs[i] = expV
				probSum += probs[i]
			}
			if probSum > 0 {
				r := rand.Float64() * probSum
				runSum := 0.0
				for i := 0; i < considerSize; i++ {
					runSum += probs[i]
					if r <= runSum {
						selectedCand = i
						break
					}
				}
			} else {
				selectedCand = 0
			}
			if selectedCand >= 0 {
				chosen := candList[selectedCand]
				if chosen.isNew {
					dispatch.Assigns[chosen.idx].AddShip(shipID, ori, des)
					dispatch.Assigns[chosen.idx].GenRoute()
					dispatch.AssignsLen++
					inserted = true
				} else {
					dispatch.Assigns[chosen.idx].AddShip(shipID, ori, des)
					dispatch.Assigns[chosen.idx].GenRoute()
					inserted = true
				}
			}
		}
		if !inserted {
			safeOrder := []int{}
			for i := 0; i < dispatch.AssignsLen; i++ {
				safeOrder = append(safeOrder, i)
			}
			rand.Shuffle(len(safeOrder), func(i, j int) {
				safeOrder[i], safeOrder[j] = safeOrder[j], safeOrder[i]
			})
			foundSafe := false
			for _, idx := range safeOrder {
				ok := dispatch.Assigns[idx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[idx].GenRoute()
					if dispatch.Assigns[idx].Cost >= 0 {
						foundSafe = true
						inserted = true
						break
					}
					dispatch.Assigns[idx].RemoveShip(shipID)
					dispatch.Assigns[idx].GenRoute()
				}
			}
			if !foundSafe && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(shipID, ori, des)
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
					dispatch.AssignsLen++
					inserted = true
				} else {
					dispatch.Assigns[dispatch.AssignsLen].RemoveShip(shipID)
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

